# Nginx config on EC2 (simplified)
server {
    listen 80;
    server_name ott.vpjoshi.in;

    # Proxy API to Node.js backend
    location /api/ {
        proxy_pass http://localhost:3000;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }

    # Proxy HLS stream (JWT protected in Node.js)
    location /stream/ {
        proxy_pass http://localhost:3000;
        proxy_buffering off;  # streaming вҖ” no buffering
    }
}

// Send transactional email via SES from Lambda
const { SESClient, SendEmailCommand } = require('@aws-sdk/client-ses');

const ses = new SESClient({ region: 'ap-south-2' });

exports.handler = async (event) => {
  const { to, subject, body } = event;

  await ses.send(new SendEmailCommand({
    Source: 'admin@unetify.in',
    Destination: { ToAddresses: [to] },
    Message: {
      Subject: { Data: subject },
      Body: {
        Html: { Data: body },
        Text: { Data: body.replace(/<[^>]*>/g, '') }
      }
    }
  }));

  return { statusCode: 200, body: 'Email sent' };
};

// Lambda auth role вҖ” DynamoDB read only
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "dynamodb:GetItem",
        "dynamodb:Query"
      ],
      "Resource": "arn:aws:dynamodb:ap-south-1:*:table/users"
    }
  ]
}

// SES Lambda role вҖ” send email only
{
  "Statement": [
    {
      "Effect": "Allow",
      "Action": ["ses:SendEmail", "ses:SendRawEmail"],
      "Resource": "arn:aws:ses:ap-south-2:*:identity/unetify.in"
    }
  ]
}

# Nginx responsibilities on EC2

1. Reverse proxy вҶ’ Docker containers
   :80/api/*    вҶ’ localhost:3000  (Node.js backend)
   :80/stream/* вҶ’ localhost:3000  (HLS server)
   :80/*        вҶ’ localhost:5173  (React frontend, dev)

2. Security headers
   X-Frame-Options: DENY
   X-Content-Type-Options: nosniff
   Referrer-Policy: strict-origin

3. Rate limiting
   limit_req_zone $binary_remote_addr zone=api:10m rate=30r/m;
   limit_req zone=api burst=10 nodelay;

4. WebSocket proxying
   proxy_http_version 1.1;
   proxy_set_header Upgrade $http_upgrade;
   proxy_set_header Connection 'upgrade';

5. Gzip compression
   gzip on;
   gzip_types application/json text/plain application/javascript;
